    const h = 7 + Math.floor(i / 2);
    const m = i % 2 === 0 ? "00" : "30";
    const ampm = h >= 12 ? "PM" : "AM";
    return ((h - 1) % 12 + 1) + ":" + m + " " + ampm;
  });

  const formatoHora = (hora) => {
    const [time, ampm] = hora.split(" ");
    let [h, m] = time.split(":").map(Number);

    if (ampm === "PM" && h !== 12) h += 12;
    if (ampm === "AM" && h === 12) h = 0;

    return { h, m };
  };

  const convertirFechaAHora12 = (fecha) => {
